#include <stdint.h>



int main(void)
{

	uint32_t *pClockReg = (uint32_t*)0x40023830;//address of clock control register(AHB1ENR)
	uint32_t *pPortDModeReg = (uint32_t*)0x40020C00;//address of the GPIOD mode register used to control mode
	uint32_t *pPortOutputReg = (uint32_t*)0x40020C14;//address of the GPIOD output data register used to write


	*pClockReg |= (1 << 3);
	*pPortDModeReg &= ~(3 << (12 * 2));
	*pPortDModeReg |= (1 <<  (12 * 2));
//	*pPortOutputReg |= 0;
	*pPortOutputReg |= (1 << 12);
	while(1);

    /* Loop forever */
	for(;;);
}
